const review = $input.first().json;
const name = review.author_name || 'there';
const rating = review.rating || 3;
const reviewText = review.review_text || '';
const firstName = name.split(' ')[0];

// Extract service mention from review text for personalization
const serviceKeywords = ['mowing', 'lawn', 'landscaping', 'fertiliz', 'aerat', 'leaf', 'snow', 'clean', 'trim', 'hedge', 'mulch', 'weed', 'spring', 'fall', 'yard', 'garden', 'grass', 'edge', 'blow', 'plow'];
let mentionedService = '';
const lowerText = reviewText.toLowerCase();
for (const kw of serviceKeywords) {
  if (lowerText.includes(kw)) {
    mentionedService = kw;
    break;
  }
}

// Template-based response drafts by star rating
let draft = '';

const fiveStarTemplates = [
  `Thank you so much, ${firstName}! We're thrilled to hear you had a great experience${mentionedService ? ' with your ' + mentionedService : ''}. Your kind words mean the world to our team. We truly love what we do, and customers like you make it all worthwhile. We look forward to keeping your yard looking amazing!\n\n- Vance, Owner of TotalGuard Yard Care`,
  `${firstName}, thank you for the wonderful review! It makes our day knowing you're happy with our work${mentionedService ? ' on your ' + mentionedService : ''}. We take pride in every yard we care for, and your feedback is the best reward. Can't wait to see you next time!\n\n- Vance, Owner of TotalGuard Yard Care`,
  `Wow, thank you ${firstName}! A 5-star review means everything to us. We put our heart into every property${mentionedService ? ', especially the ' + mentionedService : ''}, and hearing that it shows is incredibly rewarding. Thank you for trusting TotalGuard with your yard!\n\n- Vance, Owner of TotalGuard Yard Care`
];

const fourStarTemplates = [
  `Thank you for the great review, ${firstName}! We're glad you had a positive experience${mentionedService ? ' with your ' + mentionedService : ''}. We always strive for perfection, so if there's anything we could do to earn that 5th star next time, we'd love to hear about it. Your feedback helps us improve!\n\n- Vance, Owner of TotalGuard Yard Care`,
  `${firstName}, we really appreciate you taking the time to leave a review! We're happy to hear things went well${mentionedService ? ' with the ' + mentionedService : ''}. We're always looking to go above and beyond - is there anything we could do differently to make your experience perfect? We value your input!\n\n- Vance, Owner of TotalGuard Yard Care`
];

const threeStarTemplates = [
  `${firstName}, thank you for your honest feedback. We appreciate you sharing your experience${mentionedService ? ' with our ' + mentionedService + ' service' : ''}. A 3-star review tells us we have room to grow, and we take that seriously. We'd love the chance to make things right and exceed your expectations next time. Would you be open to a quick call so I can personally address your concerns? You can reach me at (608) 535-6057.\n\n- Vance, Owner of TotalGuard Yard Care`,
  `Thank you for sharing your thoughts, ${firstName}. We want every customer to have an outstanding experience, and it sounds like we fell short${mentionedService ? ' with the ' + mentionedService : ''}. I'd really appreciate the opportunity to discuss how we can do better. Please feel free to call me directly at (608) 535-6057 - I want to earn your 5 stars.\n\n- Vance, Owner of TotalGuard Yard Care`
];

const lowStarTemplates = [
  `${firstName}, I'm truly sorry to hear about your experience. This is not the standard we hold ourselves to${mentionedService ? ', especially when it comes to ' + mentionedService : ''}. I take full responsibility and want to personally make this right. Please call me directly at (608) 535-6057 so we can discuss how to fix this immediately. Your satisfaction is my top priority.\n\nSincerely,\nVance, Owner of TotalGuard Yard Care`,
  `${firstName}, I sincerely apologize for your experience. Every customer deserves excellent service, and we clearly missed the mark${mentionedService ? ' with your ' + mentionedService : ''}. I want to personally address your concerns and make things right. Please reach out to me directly at (608) 535-6057 - I will not rest until you're satisfied.\n\nSincerely,\nVance, Owner of TotalGuard Yard Care`
];

// Pick a random template based on rating
const pickRandom = (arr) => arr[Math.floor(Math.random() * arr.length)];

if (rating === 5) {
  draft = pickRandom(fiveStarTemplates);
} else if (rating === 4) {
  draft = pickRandom(fourStarTemplates);
} else if (rating === 3) {
  draft = pickRandom(threeStarTemplates);
} else {
  draft = pickRandom(lowStarTemplates);
}

return [{
  json: {
    review_id: review.review_id,
    author_name: review.author_name,
    rating: review.rating,
    review_text: review.review_text,
    is_five_star: review.is_five_star,
    response_draft: draft
  }
}];

const review = $('Generate Template Response').first().json;
const stars = '⭐'.repeat(review.rating || 1);
const socialNote = review.is_five_star ? '

🌟 QUEUED FOR SOCIAL MEDIA AMPLIFICATION' : '';

const urgencyLabel = review.rating <= 2 ? '🚨 URGENT - ' : (review.rating === 3 ? '⚠️ ATTENTION - ' : '');

const msg = `${urgencyLabel}NEW GOOGLE REVIEW ${stars}

From: ${review.author_name || 'Anonymous'}
Rating: ${review.rating}/5

“${review.review_text || 'No text provided'}”

——————————————

DRAFT RESPONSE:

${review.response_draft}

——————————————${socialNote}

Reply APPROVE to post as-is, or type your edited response.`;

return [{ json: { telegram_message: msg, review_id: review.review_id, is_five_star: review.is_five_star } }];
